function repairInvestorMojibake(value) {
  if (typeof value !== 'string') return value;
  if (!/[ÃÂÐÑãåä][\u0080-\u00ff]/.test(value)) return value;
  try {
    return decodeURIComponent(escape(value));
  } catch {
    return value;
  }
}

Object.values(investorTranslations).forEach((config) => {
  config.name = repairInvestorMojibake(config.name);
  config.metaTitle = repairInvestorMojibake(config.metaTitle);
  config.metaDescription = repairInvestorMojibake(config.metaDescription);
  config.text = new Map(
    [...config.text.entries()].map(([source, translated]) => [
      source,
      repairInvestorMojibake(translated),
    ]),
  );
});

