investorUkrainianEditorialOverrides.forEach(([source, translated]) => {
  investorTranslations.uk?.text.set(source, translated);
});

const investorSupportedLanguages = Object.keys(investorTranslations);
const investorLanguageStorageKey = 'greenhaven:landing-language';
const investorOriginalTextNodes = [];
const investorUiLabels = {
  en: {
    documentMetadata: 'Document metadata',
    siteLanguage: 'Site language',
  },
  es: {
    documentMetadata: 'Metadatos del documento',
    siteLanguage: 'Idioma del sitio',
  },
  de: {
    documentMetadata: 'Dokumentmetadaten',
    siteLanguage: 'Seitensprache',
  },
  fr: {
    documentMetadata: 'Métadonnées du document',
    siteLanguage: 'Langue du site',
  },
  ru: {
    documentMetadata: 'Метаданные документа',
    siteLanguage: 'Язык сайта',
  },
  uk: {
    documentMetadata: 'Метадані документа',
    siteLanguage: 'Мова сайту',
  },
  ja: {
    documentMetadata: '文書メタデータ',
    siteLanguage: 'サイトの言語',
  },
};

function normalizeInvestorText(value) {
  return value.replace(/\s+/g, ' ').trim();
}

function normalizeInvestorLanguage(language) {
  return language?.toLowerCase().split('-')[0] ?? '';
}

function isInvestorLanguageSupported(language) {
  return investorSupportedLanguages.includes(normalizeInvestorLanguage(language));
}

function getStoredInvestorLanguage() {
  try {
    return window.localStorage.getItem(investorLanguageStorageKey);
  } catch {
    return null;
  }
}

function detectInvestorLanguage() {
  const queryLanguage = new URLSearchParams(window.location.search).get('lang');
  if (isInvestorLanguageSupported(queryLanguage)) {
    return normalizeInvestorLanguage(queryLanguage);
  }

  const storedLanguage = getStoredInvestorLanguage();
  if (isInvestorLanguageSupported(storedLanguage)) {
    return normalizeInvestorLanguage(storedLanguage);
  }

  const browserLanguage = normalizeInvestorLanguage(window.navigator.language);
  if (isInvestorLanguageSupported(browserLanguage)) {
    return browserLanguage;
  }

  return 'en';
}

function captureInvestorTextNodes() {
  const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, {
    acceptNode(node) {
      const parent = node.parentElement;
      const tag = parent?.tagName;
      if (tag === 'STYLE' || tag === 'SCRIPT') return NodeFilter.FILTER_REJECT;
      if (parent?.closest('[data-investor-language-switcher]')) {
        return NodeFilter.FILTER_REJECT;
      }
      return normalizeInvestorText(node.nodeValue)
        ? NodeFilter.FILTER_ACCEPT
        : NodeFilter.FILTER_REJECT;
    },
  });

  while (walker.nextNode()) {
    const node = walker.currentNode;
    investorOriginalTextNodes.push({
      node,
      key: normalizeInvestorText(node.nodeValue),
      leading: node.nodeValue.match(/^\s*/)?.[0] ?? '',
      trailing: node.nodeValue.match(/\s*$/)?.[0] ?? '',
    });
  }
}

function updateInvestorLanguageUrl(language) {
  const url = new URL(window.location.href);
  url.searchParams.set('lang', language);
  window.history.replaceState(null, '', url);
}

function persistInvestorLanguage(language) {
  try {
    window.localStorage.setItem(investorLanguageStorageKey, language);
  } catch {
    // The document still works when storage is unavailable.
  }
}

function updateInvestorLanguageButtons(language) {
  document.querySelectorAll('[data-investor-lang-switch]').forEach((button) => {
    const isActive = button.dataset.investorLangSwitch === language;
    button.setAttribute('aria-pressed', String(isActive));
    button.title = investorTranslations[button.dataset.investorLangSwitch]?.name ?? '';
  });
}

function applyInvestorLanguage(language) {
  const config = investorTranslations[language] ?? investorTranslations.en;
  document.documentElement.lang = language;
  document.title = config.metaTitle;
  document
    .querySelector('meta[name="description"]')
    ?.setAttribute('content', config.metaDescription);
  document
    .querySelector('.nav')
    ?.setAttribute(
      'aria-label',
      investorUiLabels[language]?.documentMetadata ?? 'Document metadata',
    );
  document
    .querySelector('.reader-card')
    ?.setAttribute('aria-label', config.text.get('Core reader snapshot') ?? 'Core reader snapshot');
  document
    .querySelector('.contact-panel')
    ?.setAttribute('aria-label', config.text.get('Project links') ?? 'Project links');
  document
    .querySelector('[data-investor-language-switcher]')
    ?.setAttribute(
      'aria-label',
      investorUiLabels[language]?.siteLanguage ?? 'Site language',
    );
  document
    .querySelector('.brand')
    ?.setAttribute('href', `https://greenhaven.quest/?lang=${language}`);

  investorOriginalTextNodes.forEach((entry) => {
    const translated = language === 'en' ? entry.key : config.text.get(entry.key);
    if (translated) {
      entry.node.nodeValue = entry.leading + translated + entry.trailing;
    }
  });

  updateInvestorLanguageButtons(language);
}

function setInvestorLanguage(language, shouldUpdateUrl = true) {
  const normalizedLanguage = normalizeInvestorLanguage(language);
  if (!isInvestorLanguageSupported(normalizedLanguage)) return;
  persistInvestorLanguage(normalizedLanguage);
  if (shouldUpdateUrl) updateInvestorLanguageUrl(normalizedLanguage);
  applyInvestorLanguage(normalizedLanguage);
}

window.greenhavenInvestorTranslations = investorTranslations;

if (document.querySelector('[data-investor-language-switcher]')) {
  captureInvestorTextNodes();
  const initialInvestorLanguage = detectInvestorLanguage();
  applyInvestorLanguage(initialInvestorLanguage);

  document.querySelectorAll('[data-investor-lang-switch]').forEach((button) => {
    button.addEventListener('click', () => {
      setInvestorLanguage(button.dataset.investorLangSwitch);
    });
  });
}
